// Parsear entrada del webhook o Git hook
const body = $input.first().json.body ?? $input.first().json;

// Determinar si viene de Git hook o es manual
const isGitHook = body.commit || body.commits || body.pusher;

if (isGitHook) {
  // Formato GitHub/Gitea webhook
  const commits = body.commits || [];
  const changedFiles = [];

  for (const commit of commits) {
    for (const file of commit.added || []) {
      changedFiles.push({ path: file, action: 'added' });
    }
    for (const file of commit.modified || []) {
      changedFiles.push({ path: file, action: 'modified' });
    }
    for (const file of commit.removed || []) {
      changedFiles.push({ path: file, action: 'removed' });
    }
  }

  return [{
    json: {
      source: 'git',
      pusher: body.pusher?.name || 'unknown',
      repository: body.repository?.name || 'lookitry',
      branch: body.ref?.replace('refs/heads/', '') || 'main',
      changed_files: changedFiles.filter(f => 
        f.path.endsWith('.md') || 
        f.path.startsWith('docs/') ||
        ['PRD.md', 'DESIGN.md', 'TECH_STACK.md', 'REGLAS_IMPORTANTES.md', 'CHANGELOG.md'].includes(f.path)
      ),
      commit_sha: commits[0]?.id || body.after || 'unknown'
    }
  }];
} else {
  // Formato manual o script directo
  return [{
    json: {
      source: 'manual',
      files: body.files || [],
      commit: body.commit || new Date().toISOString()
    }
  }];
}

// Split batch para procesar archivos
offset: 0
count: 10

// Decodificar contenido base64 del archivo
const response = $input.first().json;

if (response.content) {
  // GitHub API returns base64 encoded content
  const content = Buffer.from(response.content.replace(/\n/g, ''), 'base64').toString('utf-8');
  const fileName = response.name || $('Parsear entrada').first().json.path.split('/').pop();

  return [{
    json: {
      file_name: fileName,
      file_path: response.path,
      content: content,
      sha: response.sha,
      commit_sha: $('Parsear entrada').first().json.commit_sha
    }
  }];
} else {
  throw new Error('No se pudo obtener contenido del archivo');
}

// Preparar archivo para Google Drive
const data = $('Decodificar contenido').first().json;

// Carpeta destino en Drive
const FOLDER_ID = $env.GDRIVE_NOTEBOOKLM_FOLDER_ID || 'LOOKITRY_PROJECT_KNOWLEDGE';

return [{
  json: {
    file_name: data.file_name,
    file_path: data.file_path,
    content: data.content,
    folder_id: FOLDER_ID,
    mimeType: 'text/markdown',
    description: `Sincronizado desde Lookitry repo - Commit: ${data.commit_sha}`
  }
}];

